const locationId = process.env.GHL_LOCATION_ID || 'TW8JsPW5NMnA3tfK2XLn';
const base = 'https://services.leadconnectorhq.com';
const headers = {
  Authorization: `Bearer ${token}`,
  Version: '2021-07-28',
  Accept: 'application/json',
  'Content-Type': 'application/json'
};

if (!token) {
  console.error('Missing GHL token env var');
  process.exit(2);
}

const sleep = (ms) => new Promise(r => setTimeout(r, ms));
let lastCall = 0;
async function api(method, endpoint, body) {
  const elapsed = Date.now() - lastCall;
  if (elapsed < 1200) await sleep(1200 - elapsed);
  lastCall = Date.now();
  const res = await fetch(base + endpoint, {
    method,
    headers,
    body: body ? JSON.stringify(body) : undefined
  });
  const txt = await res.text();
  let data = null;
  try { data = txt ? JSON.parse(txt) : null; } catch { data = { raw: txt }; }
  if (!res.ok) throw new Error(`${method} ${endpoint} -> ${res.status} ${txt?.slice(0,300)}`);
  return data;
}

function pickContacts(payload) {
  if (Array.isArray(payload?.contacts)) return payload.contacts;
  if (Array.isArray(payload?.data?.contacts)) return payload.data.contacts;
  if (Array.isArray(payload?.data)) return payload.data;
  if (Array.isArray(payload)) return payload;
  return [];
}

function toCustomFieldMap(contact) {
  const out = {};
  const cf = contact?.customFields;
  if (!cf) return out;
  if (Array.isArray(cf)) {
    for (const f of cf) {
      const key = f?.key || f?.name || f?.id;
      const val = f?.field_value ?? f?.value;
      if (key) out[key] = val;
    }
  } else if (typeof cf === 'object') {
    Object.assign(out, cf);
  }
  return out;
}

function getDate(contact) {
  const raw = contact.dateUpdated || contact.updatedAt || contact.lastActivity || contact.dateAdded;
  const t = raw ? new Date(raw).getTime() : NaN;
  return Number.isFinite(t) ? t : 0;
}

async function getConversationsCount(contactId) {
  try {
    const resp = await api('GET', `/conversations/?locationId=${locationId}&contactId=${contactId}`);
    const list = resp?.conversations || resp?.data?.conversations || resp?.data || [];
    const inboundSms = (list || []).filter(c => (c.type || '').toUpperCase() === 'SMS' && (c.direction || '').toLowerCase() === 'inbound').length;
    const first = list?.[0];
    return { inboundSms, firstDate: first?.dateAdded || first?.updatedAt || first?.lastMessageDate };
  } catch {
    return { inboundSms: 0, firstDate: null };
  }
}

function computeScore(contact, convoInfo) {
  const cf = toCustomFieldMap(contact);
  const tags = contact.tags || [];

  let score = 0;

  // Response speed
  if (convoInfo?.firstDate) {
    const hours = (Date.now() - new Date(convoInfo.firstDate).getTime()) / 36e5;
    if (hours < 1) score += 20;
    else if (hours < 24) score += 15;
    else if (hours < 72) score += 10;
    else score += 5;
  }

  // Email engagement
  if (contact.emailVerified) score += 10;
  const emailOpens = Number(cf.email_opens || cf.emailOpens || 0);
  score += Math.min(emailOpens * 2, 10);

  // SMS replies
  score += Math.min((convoInfo?.inboundSms || 0) * 5, 20);

  // Alignment
  const alignment = Number(cf.alignment_score || cf.alignmentScore || 0);
  score += Math.round((Math.max(0, Math.min(100, alignment)) / 100) * 20);

  // Completion tags
  if (tags.includes('scorecard-lead')) score += 10;
  if (tags.includes('ebook-buyer')) score += 10;

  return Math.max(0, Math.min(100, Math.round(score)));
}

async function updateLeadScore(contactId, score) {
  // key-based custom field update
  return api('PUT', `/contacts/${contactId}`, {
    customFields: [
      { key: 'lead_score', field_value: String(score) }
    ]
  });
}

const now = Date.now();
const sixHoursAgo = now - 6 * 3600 * 1000;

// Pull a broad recent slice, then filter to last 6h locally
const batch = await api('GET', `/contacts/?locationId=${locationId}&limit=200`);
const contacts = pickContacts(batch);
const recent = contacts.filter(c => getDate(c) >= sixHoursAgo);

const hot = [];
for (const c of recent) {
  const id = c.id || c._id;
  if (!id) continue;
  const convo = await getConversationsCount(id);
  const score = computeScore(c, convo);
  await updateLeadScore(id, score);
  if (score >= 90) {
    hot.push({
      id,
      name: [c.firstName, c.lastName].filter(Boolean).join(' ').trim() || c.name || c.email || c.phone || id,
      score
    });
  }
}

if (hot.length === 0) {
  console.log('');
} else {
  const lines = hot
    .sort((a,b) => b.score - a.score)
    .map(h => `- ${h.name} (${h.score}) [${h.id}]`)
    .join('\n');
  console.log(`🚨 HOT LEADS (90+) in last 6h: ${hot.length}\n${lines}`);
}

